import{_ as a,o as t,c as o,s as n}from"./chunks/framework.Dgctdl0s.js";const d=JSON.parse(`{"title":"pnpm 11 Beta 2: Major Store & Global Package Overhauls","description":"pnpm's latest beta brings substantial changes to its package store, including SQLite integration and an optimized index format, alongside a new approach to isolated global packages.","frontmatter":{"layout":"article","title":"pnpm 11 Beta 2: Major Store & Global Package Overhauls","description":"pnpm's latest beta brings substantial changes to its package store, including SQLite integration and an optimized index format, alongside a new approach to isolated global packages.","photo":"https://opengraph.githubassets.com/7367dfbf813c158a9b5fb7b0b448de96ba715300398018d45c58be65744eb742/pnpm/pnpm/releases/tag/v11.0.0-beta.2","original_url":"https://github.com/pnpm/pnpm/releases/tag/v11.0.0-beta.2","source_name":"pnpm Releases","source_author":null,"tags":["nodejs","build-tools","release","performance"],"significance":3,"head":[["meta",{"property":"og:type","content":"article"}],["meta",{"property":"og:title","content":"pnpm 11 Beta 2: Major Store & Global Package Overhauls"}],["meta",{"property":"og:description","content":"pnpm's latest beta brings substantial changes to its package store, including SQLite integration and an optimized index format, alongside a new approach to isolated global packages."}],["meta",{"property":"og:url","content":"https://www.frsource.org/digestweb//articles/2026-03-21/pnpm-11-beta-2-major-store-global-package-overhauls"}],["meta",{"property":"og:site_name","content":"digestweb.dev"}],["meta",{"property":"og:image","content":"https://opengraph.githubassets.com/7367dfbf813c158a9b5fb7b0b448de96ba715300398018d45c58be65744eb742/pnpm/pnpm/releases/tag/v11.0.0-beta.2"}],["meta",{"name":"twitter:card","content":"summary_large_image"}],["meta",{"name":"twitter:title","content":"pnpm 11 Beta 2: Major Store & Global Package Overhauls"}],["meta",{"name":"twitter:description","content":"pnpm's latest beta brings substantial changes to its package store, including SQLite integration and an optimized index format, alongside a new approach to isolated global packages."}],["meta",{"name":"twitter:image","content":"https://opengraph.githubassets.com/7367dfbf813c158a9b5fb7b0b448de96ba715300398018d45c58be65744eb742/pnpm/pnpm/releases/tag/v11.0.0-beta.2"}]]},"headers":[],"relativePath":"articles/2026-03-21/pnpm-11-beta-2-major-store-global-package-overhauls.md","filePath":"articles/2026-03-21/pnpm-11-beta-2-major-store-global-package-overhauls.md"}`),s={name:"articles/2026-03-21/pnpm-11-beta-2-major-store-global-package-overhauls.md"};function i(r,e,l,p,c,g){return t(),o("div",null,[...e[0]||(e[0]=[n('<h2 id="summary-key-takeaways" tabindex="-1">Summary &amp; Key Takeaways <a class="header-anchor" href="#summary-key-takeaways" aria-label="Permalink to “Summary &amp; Key Takeaways”">​</a></h2><ul><li><strong>Store Architecture Overhaul</strong>: pnpm 11 introduces a new store version (v11) with significant changes.</li><li><strong>SQLite Integration</strong>: Package index data is now stored in a single SQLite database, replacing individual JSON files, to reduce I/O and improve space efficiency.</li><li><strong>Optimized Index Format</strong>: The index file format is optimized to store hash algorithms once and use hex digests, improving performance for path lookups.</li><li><strong>Bundled Manifests</strong>: Package manifests are now stored directly in the index, reducing the need to read <code>package.json</code> files during resolution and installation.</li><li><strong>Global Virtual Store</strong>: Global installs (<code>pnpm add -g</code>) and <code>pnpm dlx</code> now default to using the global virtual store.</li><li><strong>Isolated Global Packages</strong>: Each globally installed package gets its own isolated directory, preventing conflicts and improving consistency.</li></ul><h2 id="our-commentary" tabindex="-1">Our Commentary <a class="header-anchor" href="#our-commentary" aria-label="Permalink to “Our Commentary”">​</a></h2><p>This is a pretty big deal for pnpm users, and honestly, for anyone in the Node.js ecosystem who cares about package management efficiency. The move to SQLite for the package index is a smart play; we&#39;ve seen similar shifts in other tools to combat filesystem overhead, and it usually pays off in spades for performance. The idea of isolated global packages is also a huge win for developer experience. How many times have we wrestled with conflicting global tools? This change should make that a thing of the past, which is a relief. It&#39;s still a beta, but these are the kinds of foundational improvements that make a package manager truly robust. We&#39;re excited to see how this lands in a stable release.</p>',4)])])}const h=a(s,[["render",i]]);export{d as __pageData,h as default};
